// Extracts ONLY the `group_*` attribute-group headers from the admin i18n dictionaries into a
// tiny runtime module. widgetUtils bridges those into the legacy `window.systemDictionary` so
// custom group headers render (see widgetUtils registerGroupLabels). The full admin dictionary
// (~500 kB) stays behind the `./translations` module-federation expose, which the vis-2 EDITOR
// loads on demand for field labels; the RUNTIME must not pull it just for a handful of headers.
//
// Regenerated by tasks.js before every widget build; committed so lint/test/standalone build see
// it. A vitest test (groupLabels sync) guards against drift.
const { readFileSync, writeFileSync, mkdirSync } = require('node:fs');
const { join } = require('node:path');

const ROOT = join(__dirname, '..');
const LANGS = ['en', 'de', 'es', 'fr', 'it', 'nl', 'pl', 'pt', 'ru', 'uk', 'zh-cn'];

function build() {
    const out = {};
    for (const lang of LANGS) {
        const dict = JSON.parse(readFileSync(join(ROOT, 'admin/i18n', `${lang}.json`), 'utf8'));
        const groups = {};
        for (const key of Object.keys(dict)) {
            if (key.startsWith('group_')) {
                groups[key] = dict[key];
            }
        }
        out[lang] = groups;
    }
    return out;
}

function write(data) {
    const dir = join(ROOT, 'src-widgets-ts/src/generated');
    mkdirSync(dir, { recursive: true });
    // trailing newline keeps the committed artifact diff-clean
    writeFileSync(join(dir, 'groupLabels.json'), `${JSON.stringify(data, null, 4)}\n`);
}

function generate() {
    write(build());
}

if (require.main === module) {
    generate();
}

module.exports = { build, generate };
